import { useEffect, useRef, useState } from 'react';
import { motion } from 'framer-motion';
import CountUp from 'react-countup';
import { TrendingUp, Users, Eye, Calendar, Sparkles } from 'lucide-react';
import { Card } from './ui/card';

const MetricCard = ({ icon: Icon, label, value, suffix = '', prefix = '', delay = 0, color = 'fuchsia' }) => {
  const [isVisible, setIsVisible] = useState(false);
  const ref = useRef(null);

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setIsVisible(true);
        }
      },
      { threshold: 0.3 }
    );

    if (ref.current) {
      observer.observe(ref.current);
    }

    return () => observer.disconnect();
  }, []);

  const colorClasses = {
    fuchsia: 'from-fuchsia-400 to-purple-500 text-fuchsia-400',
    green: 'from-emerald-400 to-teal-500 text-emerald-400',
    blue: 'from-blue-400 to-indigo-500 text-blue-400',
    amber: 'from-amber-400 to-orange-500 text-amber-400'
  };

  return (
    <motion.div
      ref={ref}
      initial={{ opacity: 0, y: 30 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.6, delay }}
      className="text-center"
    >
      <div className={`inline-flex items-center justify-center w-12 h-12 rounded-full bg-gradient-to-br ${colorClasses[color].split(' ').slice(0, 2).join(' ')} bg-opacity-20 mb-3`}>
        <Icon className={`w-6 h-6 ${colorClasses[color].split(' ').pop()}`} />
      </div>
      <div className="font-mono font-bold text-2xl md:text-3xl gradient-text" data-testid={`metric-${label.toLowerCase().replace(/\s/g, '-')}`}>
        {prefix}
        {isVisible ? (
          <CountUp
            end={value}
            duration={2.5}
            separator=","
            suffix={suffix}
            decimals={suffix === 'M' ? 1 : 0}
            useEasing={true}
          />
        ) : '0'}
      </div>
      <p className="text-sm text-muted-foreground mt-1">{label}</p>
    </motion.div>
  );
};

export const CaseStudyMetrics = () => {
  return (
    <section className="py-12 px-4 md:px-0" data-testid="case-study-section">
      <motion.div
        initial={{ opacity: 0, y: 40 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.8 }}
      >
        <Card className="relative overflow-hidden border-0 bg-gradient-to-br from-fuchsia-500/10 via-purple-500/5 to-transparent dark:glass-card light:glass-card-light">
          {/* Decorative Elements */}
          <div className="absolute top-0 right-0 w-64 h-64 bg-fuchsia-500/10 rounded-full blur-3xl -translate-y-1/2 translate-x-1/2" />
          <div className="absolute bottom-0 left-0 w-48 h-48 bg-purple-500/10 rounded-full blur-3xl translate-y-1/2 -translate-x-1/2" />
          
          <div className="relative z-10 p-6 md:p-10">
            {/* Header */}
            <div className="text-center mb-10">
              <motion.div
                initial={{ scale: 0 }}
                animate={{ scale: 1 }}
                transition={{ duration: 0.5, type: "spring" }}
                className="inline-flex items-center gap-2 px-4 py-2 rounded-full bg-fuchsia-500/20 text-fuchsia-400 text-sm font-medium mb-4"
              >
                <Sparkles className="w-4 h-4" />
                Case Study
              </motion.div>
              <h2 className="text-2xl md:text-3xl font-bold mb-2">
                Crecimiento Orgánico en <span className="gradient-text">90 Días</span>
              </h2>
              <p className="text-muted-foreground text-sm md:text-base">
                Estrategia de contenido viral para @sweetdeliriumcookies
              </p>
            </div>

            {/* Metrics Grid */}
            <div className="grid grid-cols-2 md:grid-cols-4 gap-8 md:gap-12">
              <MetricCard 
                icon={Users} 
                label="Seguidores Iniciales" 
                value={0} 
                delay={0.1}
                color="blue"
              />
              <MetricCard 
                icon={TrendingUp} 
                label="Seguidores Actuales" 
                value={128} 
                suffix="K"
                delay={0.2}
                color="green"
              />
              <MetricCard 
                icon={Eye} 
                label="Vistas Totales" 
                value={6.4} 
                suffix="M"
                delay={0.3}
                color="fuchsia"
              />
              <MetricCard 
                icon={Calendar} 
                label="Días de Campaña" 
                value={90} 
                delay={0.4}
                color="amber"
              />
            </div>

            {/* Growth Bar */}
            <motion.div 
              className="mt-10 pt-8 border-t border-border/50"
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={{ delay: 0.6 }}
            >
              <div className="flex items-center justify-between text-sm mb-3">
                <span className="text-muted-foreground">Progreso de crecimiento</span>
                <span className="font-mono font-semibold gradient-text">+12,800%</span>
              </div>
              <div className="h-3 bg-secondary rounded-full overflow-hidden">
                <motion.div 
                  className="h-full bg-gradient-to-r from-fuchsia-500 to-purple-500 rounded-full"
                  initial={{ width: "0%" }}
                  animate={{ width: "100%" }}
                  transition={{ duration: 2, delay: 0.8, ease: "easeOut" }}
                />
              </div>
            </motion.div>

            {/* BlyxNova Credit */}
            <motion.div 
              className="mt-8 text-center"
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={{ delay: 1 }}
            >
              <p className="text-xs text-muted-foreground">
                Estrategia desarrollada por{' '}
                <span className="blyx-brand font-semibold">BlyxNova Studio</span>
              </p>
            </motion.div>
          </div>
        </Card>
      </motion.div>
    </section>
  );
};
